// This file is automatically generated. Do not edit it directly.
import { createClient } from '@supabase/supabase-js';
import type { Database } from './types';
import { logInvokeStart, logInvokeEnd, logInvokeBlocked } from '@/lib/invokeLogger';

const SUPABASE_URL = import.meta.env.VITE_SUPABASE_URL;
const SUPABASE_PUBLISHABLE_KEY = import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY;

// Import the supabase client like this:
// import { supabase } from "@/integrations/supabase/client";

export const supabase = createClient<Database>(SUPABASE_URL, SUPABASE_PUBLISHABLE_KEY, {
  auth: {
    storage: localStorage,
    persistSession: true,
    autoRefreshToken: true,
  }
});

// ── Global invoke guard ──────────────────────────────────────────────────────
// Logs every edge-function call and hard-blocks any AI/generate/suggest
// function from being invoked (prevents unexpected AI credit usage).
const _originalInvoke = supabase.functions.invoke.bind(supabase.functions);
supabase.functions.invoke = async (fn: string, payload?: any) => {
  console.error('[TRACE INVOKE]', fn, new Error().stack);

  if (fn.includes('ai') || fn.includes('generate') || fn.includes('suggest') || fn.includes('task') || fn.includes('review')) {
    const msg = `BLOCKED_AT_INVOKE_LAYER: "${fn}" is an AI function and must not be called automatically`;
    console.error('[AI CALL BLOCKED]', fn);
    logInvokeBlocked(fn, msg);
    throw new Error(msg);
  }

  const callId = logInvokeStart(fn, payload?.body);
  const t0 = Date.now();
  try {
    const result = await _originalInvoke(fn, payload);
    logInvokeEnd(callId, result.error ? 'error' : 'success', Date.now() - t0, result.error?.message);
    return result;
  } catch (err: any) {
    logInvokeEnd(callId, 'error', Date.now() - t0, err?.message ?? 'Unknown error');
    throw err;
  }
};